# server.py -- WebSocket server with FastAPI that streams LLM tokens

import json
import anthropic
from fastapi import FastAPI, WebSocket, WebSocketDisconnect
from starlette.websockets import WebSocketState

app = FastAPI()
client = anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env


@app.websocket("/ws/chat")
async def chat_endpoint(ws: WebSocket):
    await ws.accept()
    try:
        while True:
            # 1. Receive a message from the client
            raw = await ws.receive_text()
            msg = json.loads(raw)
            user_text = msg.get("content", "")

            # 2. Stream the LLM response token by token
            with client.messages.stream(
                model="claude-opus-4-5",
                max_tokens=1024,
                messages=[{"role": "user", "content": user_text}],
            ) as stream:
                for text_chunk in stream.text_stream:
                    # 3. Push each token delta immediately
                    if ws.client_state == WebSocketState.CONNECTED:
                        await ws.send_text(json.dumps({
                            "type": "token",
                            "text": text_chunk,
                        }))

            # 4. Signal completion with token usage
            usage = stream.get_final_message().usage
            await ws.send_text(json.dumps({
                "type": "done",
                "usage": {
                    "input_tokens": usage.input_tokens,
                    "output_tokens": usage.output_tokens,
                },
            }))

    except WebSocketDisconnect:
        pass  # Client closed -- normal, no action needed

# agent_ws.py -- agent that emits structured events over WebSocket

import json
import anthropic
from fastapi import FastAPI, WebSocket, WebSocketDisconnect

app = FastAPI()
client = anthropic.Anthropic()

TOOLS = [{
    "name": "web_search",
    "description": "Search the web for current information.",
    "input_schema": {
        "type": "object",
        "properties": {"query": {"type": "string"}},
        "required": ["query"],
    },
}]


def stub_search(query: str) -> str:
    return f"Results for '{query}': [r1] [r2] [r3]"


async def run_agent(ws: WebSocket, user_message: str) -> None:
    messages = [{"role": "user", "content": user_message}]

    while True:
        with client.messages.stream(
            model="claude-opus-4-5",
            max_tokens=2048,
            tools=TOOLS,
            messages=messages,
        ) as stream:
            for event in stream:
                if not hasattr(event, "type"):
                    continue
                if event.type == "content_block_start":
                    cb = event.content_block
                    if getattr(cb, "type", None) == "tool_use":
                        await ws.send_text(json.dumps({
                            "type": "tool_start",
                            "tool": cb.name,
                            "id": cb.id,
                        }))
                elif event.type == "content_block_delta":
                    if hasattr(event.delta, "text"):
                        await ws.send_text(json.dumps({
                            "type": "token",
                            "text": event.delta.text,
                        }))
            final = stream.get_final_message()

        messages.append({"role": "assistant", "content": final.content})

        if final.stop_reason != "tool_use":
            break  # Agent finished

        tool_results = []
        for block in final.content:
            if block.type == "tool_use":
                result = stub_search(block.input["query"])
                await ws.send_text(json.dumps({
                    "type": "tool_result",
                    "tool": block.name,
                    "snippet": result[:120],
                }))
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
        messages.append({"role": "user", "content": tool_results})

    await ws.send_text(json.dumps({"type": "done"}))


@app.websocket("/ws/agent")
async def agent_endpoint(ws: WebSocket):
    await ws.accept()
    try:
        raw = await ws.receive_text()
        msg = json.loads(raw)
        await run_agent(ws, msg["content"])
    except WebSocketDisconnect:
        pass
